import React from 'react';

const Cultura = ({ sitios }) => {
    return (
        <div style={{ padding: '20px' }}>
            <h1 style={{ textAlign: 'center' }}>Sitios Culturales de La Paz</h1>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' }}>
                {sitios.map((sitio) => (
                    <div key={sitio.id_sitio} style={{ border: '1px solid #ddd', borderRadius: '10px', padding: '15px', backgroundColor: '#f9f9f9' }}>
                        <h2 style={{ color: '#2c3e50' }}>{sitio.nombre}</h2>
                        <p>{sitio.descripcion}</p>
                        <small style={{ color: '#7f8c8d' }}>{sitio.direccion}</small>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Cultura;
